                       <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 800, marginBottom: '0.6rem' }}>{t.affiliate.add_modal.commission}</label>
                       <input className="input-executive" type="number" value={newPartner.commission} onChange={e => setNewPartner({...newPartner, commission: e.target.value})} />
                    </div>
                  </div>
               </div>

               <div style={{ marginTop: '3rem', display: 'flex', gap: '1rem' }}>
                  <button onClick={() => setShowAddModal(false)} className="btn-executive" style={{ flex: 1, background: 'var(--surface-container-high)', color: 'var(--primary)', border: 'none' }}>{t.cancel || (t.lang === 'ar' ? 'إلغاء' : 'Cancel')}</button>
