        <div style={{ background: 'var(--secondary)', padding: '0.85rem', borderRadius: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--primary)', boxShadow: '0 6px 12px rgba(0,0,0,0.15)' }}>
