      const file = e.target.files[0];
      setFileName(file.name);
      setStep(2);
    }
  };

  const handleClearData = async () => {
    if (window.confirm(t.lang === 'ar' ? 'هل أنت متأكد من مسح كافة البيانات؟ لا يمكن التراجع عن هذه الخطوة.' : 'Are you sure you want to clear all data? This cannot be undone.')) {
