        setImporting(false);
        setStep(3);
        showToast(t.lang === 'ar' ? 'اكتملت مواءمة البيانات السيادية' : 'Sovereign data mirroring complete', 'success');
      }, 2500);
    } catch (err) {
      console.error(err);
      setImporting(false);
      showToast('Error seeding database', 'error');
    }
  };

  const startImport = async () => {
    setImporting(true);
    // Simulate real parsing delay
    setTimeout(() => {
      setImporting(false);
      setStep(3);
      setRecordCount(1240);
