interface Campaign {
  id: string;
  name: string;
  status: string;
  reach: string;
  engagement: string;
  budget: number;
  date: string;
  category?: string;
  start_date?: string;
  leads?: string | number;
}

interface MarketingProps {
  showToast: (msg: string, type?: string) => void;
  t: Translations;
}

export default function MarketingView({ showToast, t }: MarketingProps) {
  const [activeTab, setActiveTab] = useState('campaigns');
  const [loading, setLoading] = useState(false);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);

  // Form State
  const [newCampaign, setNewCampaign] = useState({
    name: '',
    budget: '',
    start_date: new Date().toISOString().split('T')[0],
    category: 'Universal'
  });

  const fetchCampaigns = useCallback(async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('marketing_campaigns')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      if (data && data.length > 0) {
        setCampaigns(data);
      } else {
        const defaults = [
          { id: '1', name: 'Q2 Sovereign Growth', status: 'Active', reach: '124.5k', engagement: '18.2%', budget: 45000, date: '2026-03-01' },
          { id: '2', name: 'Institutional Awareness', status: 'Active', reach: '89.2k', engagement: '12.5%', budget: 15000, date: '2026-03-15' },
          { id: '3', name: 'Affiliate Recruitment Drive', status: 'Scheduled', reach: '0', engagement: '0%', budget: 10000, date: '2026-04-10' },
          { id: '4', name: 'ZATCA Compliance Webinar', status: 'Completed', reach: '45k', engagement: '25.7%', budget: 5000, date: '2026-02-10' }
        ];
        await supabase.from('marketing_campaigns').insert(defaults);
        setCampaigns(defaults);
      }
    } catch (err) {
      console.error('Marketing Fetch Error:', err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCampaigns();
  }, [fetchCampaigns]);

  const handleAddCampaign = async () => {
    if (!newCampaign.name || !newCampaign.budget) {
      showToast(t.lang === 'ar' ? 'يرجى إكمال بيانات الحملة' : 'Please complete campaign data', 'error');
      return;
    }

    setLoading(true);
    try {
      const { error } = await supabase.from('marketing_campaigns').insert([{
        name: newCampaign.name,
        budget: parseFloat(newCampaign.budget),
        status: 'Scheduled',
        category: newCampaign.category,
        start_date: newCampaign.start_date
      }]);

      if (error) throw error;

      showToast(t.lang === 'ar' ? 'تم إنشاء الحملة بنجاح' : 'Campaign created successfully', 'success');
      setShowAddModal(false);
      setNewCampaign({ name: '', budget: '', start_date: new Date().toISOString().split('T')[0], category: 'Institutional' });
      fetchCampaigns();
    } catch (err: any) {
      showToast(err.message || 'Error creating campaign', 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleSendEmail = async () => {
    setLoading(true);
    await new Promise(r => setTimeout(r, 1500));
    showToast(t.lang === 'ar' ? 'تمت جدولة إرسال 12,450 بريد إلكتروني للحملة السيادية' : 'Scheduled 12,450 emails for Sovereign Campaign', 'success');
    setLoading(false);
  };

  const handleApplyOptimization = async () => {
    setLoading(true);
    try {
      await supabase.from('system_logs').insert([{
        action: 'MARKETING_AI_OPTIMIZATION',
        details: 'Applied budget reallocation across active nodes tracking institutional shift'
      }]);
